function parseRange(s) {
  const rangeMatch = s.match(/^(-?\d+)-(-?\d+)$/);
  if (rangeMatch) {
    const a = parseInt(rangeMatch[1], 10);
    const b = parseInt(rangeMatch[2], 10);
    const result = [];
    if (a <= b) {
      for (let i = a; i <= b; i++) result.push(i);
    } else {
      for (let i = a; i >= b; i--) result.push(i);
    }
    return result;
  }
  if (/^-?\d+$/.test(s)) {
    return [parseInt(s, 10)];
  }
  return [];
}
